import { Component } from "react";
import Slider from "react-slick";

import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";

class MiSlider extends Component {
    render(){
        const settings = {
            dots: true,
            infinite: true,
            speed: 500,
            slidesToShow: 1,
            slidesToScroll: 1,
            autoplay: true,
            autoplaySpeed: 8000,
            vertical: true,
        };

        return(
            <Slider className="slider"{...settings}>
                <div className="slide">
                    <h3>Slide 1</h3>
                </div>
                <div >
                    <h3 className="slide">Slide 2</h3>
                </div>
                <div className="slide">
                    <h3>Slide 3</h3>
                </div>
            </Slider>
        )
    }
}

export default MiSlider
